// Group classes by parent contact info
const items = $input.all();
const parentMap = new Map();

for (const item of items) {
  const parentKey = `${item.json.parent_name}|${item.json.email}|${item.json.phone_number}`;

  if (!parentMap.has(parentKey)) {
    parentMap.set(parentKey, {
      parentName: item.json.parent_name,
      email: item.json.email,
      phoneNumber: item.json.phone_number,
      studentName: item.json.student_name,
      classes: []
    });
  }

  parentMap.get(parentKey).classes.push({
    subject: item.json.subject,
    startTime: item.json.start_time,
    endTime: item.json.end_time,
    meetingLink: item.json.meeting_link,
    teacherEmail: item.json.teacher_email,
    notes: item.json.notes
  });
}

// Convert map to array and sort classes by time
const result = Array.from(parentMap.values()).map(parent => {
  parent.classes.sort((a, b) => a.startTime.localeCompare(b.startTime));
  return parent;
});

return result.map(r => ({ json: r }));

const parent = $input.first().json;

let message = `📚 *Schedule for ${parent.studentName}*\n\n`;

for (const cls of parent.classes) {
  message += `⏰ ${cls.startTime} - ${cls.endTime}\n`;
  message += `📖 *${cls.subject}*\n`;
  if (cls.meetingLink) {
    message += `🔗 [Join Class](${cls.meetingLink})\n`;
  }
  if (cls.notes) {
    message += `📝 ${cls.notes}\n`;
  }
  message += `\n`;
}

message += `_Having trouble? Contact your school._`;

return [{ json: { chatId: parent.phoneNumber, message: message } }];
